class Solution {
public:
    vector<bool> friendRequests(int n, vector<vector<int>>& restrictions, vector<vector<int>>& requests) {
        struct DSU {
            vector<int> parent;
            vector<int> rank;
            DSU(int n) {
                parent.resize(n);
                rank.resize(n);
                for (int i = 0; i < n; ++i) {
                    parent[i] = i;
                }
            }
            int find(int x) {
                if (parent[x] != x) {
                    parent[x] = find(parent[x]);
                }
                return parent[x];
            }
            bool unite(int x, int y) {
                int rootX = find(x);
                int rootY = find(y);
                if (rootX == rootY) return false;
                if (rank[rootX] < rank[rootY]) {
                    parent[rootX] = rootY;
                    rank[rootY]++;
                } else {
                    parent[rootY] = rootX;
                    rank[rootX]++;
                }
                return true;
            }
        };
        vector<bool> result;
        DSU dsu(n);
        for (auto &req : requests) {
            int u = req[0];
            int v = req[1];
            bool success = true;
            if (dsu.find(u) == dsu.find(v)) {
                // already connected
            } else {
                for (auto &r : restrictions) {
                    int x = r[0], y = r[1];
                    if ((dsu.find(u) == dsu.find(x) && dsu.find(v) == dsu.find(y)) ||
                        (dsu.find(u) == dsu.find(y) && dsu.find(v) == dsu.find(x))) {
                        success = false;
                        break;
                    }
                }
            }
            if (success) {
                dsu.unite(u, v);
                result.push_back(true);
            } else {
                result.push_back(false);
            }
        }
        return result;
    }
};

